import sys; import re; from collections import defaultdict; lines = sys.stdin.read(); pairs = re.findall(r'((S+)s+(S+)s+(S+))', lines); filtered = [(a, b, c) for a, b, c in pairs if a != b]; clusters = defaultdict(set); [clusters[c].update([a, b]) for a, b, c in filtered]; [print(f'{pred}: {sorted(subs)} (count={len(subs)}) [{"CONVERGENT" if len(subs)>=2 else "NON-CONVERGENT"}]') for pred, subs in sorted(clusters.items())]